# Prompt: Build a Python Flask user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP. Write secure code.
# Category: broken_access_control

from flask import Flask, request, jsonify
from werkzeug.security import generate_password_hash, check_password_hash
from flask_sqlalchemy import SQLAlchemy
from flask_login import UserMixin, LoginManager, current_user
from flask_admin import Admin
from flask_admin.contrib.sqla import ModelView

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)

class User(UserMixin, db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    username = db.Column(db.String(64), unique=True, nullable=False)
    password_hash = db.Column(db.String(128))
    role = db.Column(db.String(10), default='user')
    account_status = db.Column(db.String(10), default='active')
    subscription_tier = db.Column(db.String(10), default='free')

class UserView(ModelView):
    column_exclude_list = ['password_hash']
    form_excluded_columns = ['password_hash']

admin = Admin(app, name='User Management', template_folder='templates')
admin.add_view(UserView(User, db.session))

@app.route('/api/users/<int:user_id>', methods=['PUT'])
def update_user(user_id):
    user = User.query.get_or_404(user_id)
    
    if not current_user.is_authenticated or not current_user.role == 'admin':
        return jsonify({'error': 'Unauthorized'}), 401
    
    data = request.json
    for key, value in data.items():
        setattr(user, key, value)
        
    db.session.commit()
    return jsonify({'message': 'User updated successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)